const profileReducer = (state, action) => {
  switch (action.type) {
    case "GET_PROFILE":
    case "UPDATE_PROFILE":
      return {
        ...state,
        profile: action.payload,
        loading: false,
      }
    case "GET_PROFILES":
      return {
        ...state,
        profiles: action.payload,
        loading: false,
      }
    case "GET_GITHUB_STATS":
      return {
        ...state,
        githubStats: action.payload,
        loading: false,
      }
    case "GET_MEDIUM_ARTICLES":
      return {
        ...state,
        mediumArticles: action.payload,
        loading: false,
      }
    case "PROFILE_ERROR":
      return {
        ...state,
        error: action.payload,
        loading: false,
      }
    case "CLEAR_PROFILE":
      return {
        ...state,
        profile: null,
        githubStats: null,
        mediumArticles: null,
        loading: false,
      }
    default:
      return state
  }
}

export default profileReducer
